CREATE TAG cost_center COMMENT = 'cost_center tag';

CREATE OR REPLACE TAG fruit_type ALLOWED_VALUES 'apple', 'banana', 'watermelon';

CREATE TAG propagate_tag PROPAGATE = ON_DEPENDENCY_AND_DATA_MOVEMENT;

CREATE TAG propagate_tag_with_conflict PROPAGATE = ON_DATA_MOVEMENT ON_CONFLICT = 'CONFLICT';

CREATE TAG full_tag ALLOWED_VALUES 'a', 'b' PROPAGATE = ON_DEPENDENCY ON_CONFLICT = ALLOWED_VALUES_SEQUENCE COMMENT = 'test';